import { Edit as EditIcon, CreditCard as CreditCardIcon, MonetizationOn as MonetizationOnIcon } from "@mui/icons-material";
import { Card, CardContent, Divider, FormControlLabel, IconButton, Radio, RadioGroup, TextField, debounce, useMediaQuery } from "@mui/material";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import Grid from "@mui/material/Grid";
import Typography from "@mui/material/Typography";
import { useTheme } from '@mui/material/styles';
import React, { useCallback, useEffect, useState } from "react";
import ButtonInput from "../components/ButtonInput/ButtonInput";
import ChangeEmailDialog from "../components/ChangeEmailDialog";
import CustomButton from "../components/CustomButton/CustomButton";
import Layout from "../components/Layout";
import ShippingCard from "../components/ShippingCard";
import useAddress from "../storage/useAddress";
import useUser from "../storage/useUser";
import { IAddress, IUser } from "../types/types";
import { formatCep, formatCoupon, formatCpf, formatPhone, getCookie, validateCpf, validateEmail, validateName, validatePhone } from "../utils/utils";
import MercadoPagoCheckout, { getCardToken } from "../components/MercadoPagoCheckout";

const debugColors = ['white', 'white', 'white', 'white', 'white', 'white', 'white', 'white']
// const debugColors = ['red', 'green', 'pink', 'blue', 'gray', 'lightBlue', 'orange', 'yellow']

enum Steps { Identification, Shipping, Payment }

type InputType = {
    value: string;
    error: boolean;
};

type Identification = {
    email: InputType;
    firstName: InputType;
    lastName: InputType;
    cpf: InputType;
    phone: InputType;
}

type Address = {
    cep: InputType;
    street: InputType;
    number: InputType;
    complement: InputType;
    neighborhood: InputType;
    city: InputType;
    state: InputType;
}

type PaymentType = "creditCard" | "pix";

type PayOptions = {
    label: string;
    value: PaymentType;
    icon: any;
}

export default function Checkout() {
    const theme = useTheme();
    const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'));
    const { isLogged, getUserDataFromApi } = useUser();
    const userIsLogged = isLogged();
    const { cacheAddress, searchCepAndStoreLocal } = useAddress();

    const [cepFound, setCepFound] = useState<boolean>(false);
    const [isLoadingCep, setIsLoadingCep] = useState<boolean>(false)
    const [isOpenModalChangeEmail, setIsOpenModalChangeEmail] = useState<boolean>(false);
    const [step, setStep] = useState<Steps>(userIsLogged ? Steps.Shipping : Steps.Shipping);

    const [paymentType, setPaymentType] = useState<PaymentType | "">("");

    const [identification, setIdentification] = useState<Identification>({
        email: { value: '', error: false },
        firstName: { value: '', error: false },
        lastName: { value: '', error: false },
        cpf: { value: '', error: false },
        phone: { value: '', error: false },
    });

    // TODO: Se usuário tiver logado, puxar endereço do usuario, se não, puxar do localStorage (useAddress).
    const [address, setAddress] = useState<Address>({
        cep: { value: '', error: false },
        street: { value: '', error: false },
        number: { value: '', error: false },
        complement: { value: '', error: false },
        neighborhood: { value: '', error: false },
        city: { value: '', error: false },
        state: { value: '', error: false },
    });


    const goToStep = (newStep: Steps) => {
        setStep(newStep);
    }

    const setError = (key: keyof Identification) => {
        setIdentification((prev) => ({
            ...prev,
            [key]: { ...prev[key], error: true }
        }))
    }

    const setAddressError = (key: keyof Address) => {
        setAddress((prev) => ({
            ...prev,
            [key]: { ...prev[key], error: true }
        }))
    }

    const getErrorMsg = (key: keyof Identification, label: string): string => {
        const input = identification[key]
        if (input?.error) {
            if (input.value.length === 0) return 'Campo obrigatório';
            else return `${label} inválido`;
        } else {
            return ''
        }
    }

    const getAddressErrorMsg = (key: keyof Address, label: string): string => {
        const input = address[key]
        if (input?.error) {
            if (input.value.length === 0) return 'Campo obrigatório';
            else return `${label} inválido`;
        } else {
            return ''
        }
    }

    const handleChangeCep = (newCep: string) => {
        setAddress((prev) => ({
            ...prev,
            cep: { value: newCep, error: false },
        }))
        applyCep(newCep);
    }

    const applyCep = (newCep: string) => {
        const cepAux = newCep.replace(/\D/g, '')
        if (cepAux.length === 8) {
            setIsLoadingCep(true);
            searchCepAndStoreLocal(cepAux)
                .then((address: IAddress) => {
                    setCepFound(true);
                    setAddress((prev) => ({
                        ...prev,
                        cep: { ...prev.cep, error: false },
                        street: { value: address.street, error: false },
                        neighborhood: { value: address.neighborhood, error: false },
                        city: { value: address.city, error: false },
                        state: { value: address.state, error: false },
                    }))
                    // TODO: chamar api carrinho para recalcular CEP
                })
                .catch((err: string) => {
                    console.log('err: ', err);
                    setAddress((prev) => ({
                        ...prev,
                        cep: { value: formatCep(cepAux), error: true },
                    }))
                    setCepFound(false);
                }).finally(() => setIsLoadingCep(false))
        } else {
            setCepFound(false);
        }
    }

    const handleBuy = async () => {
        if (!paymentType) {
            // TODO: trocar alert
            alert('Por favor, selecione a forma de pagamento');
        } else {
            const cardToken = await getCardToken();
            console.log('token:', cardToken);
        }
    }

    const handleIdentification = (e: React.FormEvent) => {
        e.preventDefault();
        let hasError = false;
        if (!validateEmail(identification.email.value)) {
            setError("email")
            hasError = true
        }
        if (!validateName(identification.firstName.value)) {
            setError("firstName")
            hasError = true
        }
        if (!validateName(identification.lastName.value)) {
            setError("lastName")
            hasError = true
        }
        if (!validateCpf(identification.cpf.value)) {
            setError("cpf")
            hasError = true
        }
        if (!validatePhone(identification.phone.value)) {
            setError("phone")
            hasError = true
        }
        if (!hasError) goToStep(Steps.Shipping);
    }

    const handleAddress = (e: React.FormEvent) => {
        e.preventDefault();
        let hasError = false;

        if (!cepFound) {
            setAddressError("cep")
            hasError = true
        }

        if (!validateName(address.street.value)) {
            setAddressError("street")
            hasError = true
        }

        if (!address.number.value) {
            setAddressError("number")
            hasError = true
        }

        if (!validateName(address.neighborhood.value)) {
            setAddressError("neighborhood")
            hasError = true
        }

        if (!hasError) goToStep(Steps.Payment);
    }

    useEffect(() => {
        if (userIsLogged) {
            getUserDataFromApi().then((userRes: IUser) => {
                setIdentification({
                    email: { value: userRes.email, error: false },
                    firstName: { value: userRes.firstName, error: false },
                    lastName: { value: userRes.lastName, error: false },
                    cpf: { value: formatCpf(userRes.document), error: false },
                    phone: { value: formatPhone(userRes.phone), error: false }
                })
                setCepFound(true);
                setAddress({
                    cep: { value: formatCep(userRes.zipcode), error: false },
                    street: { value: userRes.street, error: false },
                    number: { value: userRes.number, error: false },
                    complement: { value: userRes.complement, error: false },
                    neighborhood: { value: userRes.neighborhood, error: false },
                    city: { value: userRes.city, error: false },
                    state: { value: userRes.state, error: false },
                })
            }).catch((e) => {
                console.log(e)
            })
        } else {
            const email = getCookie('email');
            if (email) {
                setIdentification((prev) => ({
                    ...prev,
                    email: { value: email, error: false },
                }))
            }
            if (cacheAddress?.cep) {
                setCepFound(true);
                setAddress({
                    cep: { value: formatCep(cacheAddress.cep), error: false },
                    street: { value: cacheAddress.street, error: false },
                    number: { value: '', error: false },
                    complement: { value: '', error: false },
                    neighborhood: { value: cacheAddress.neighborhood, error: false },
                    city: { value: cacheAddress.city, error: false },
                    state: { value: cacheAddress.state, error: false },
                })
            }
            // TODO: chamar api de carrinho e setar valores (considerando cep)
        }
    }, [])

    const renderIdentificationForm = () => (
        <>
            <ChangeEmailDialog
                isOpen={isOpenModalChangeEmail}
                onClose={() => setIsOpenModalChangeEmail(false)}
                value={identification.email.value}
                onChange={(editedEmail) =>
                    setIdentification((prev) => ({
                        ...prev,
                        email: { value: editedEmail, error: false },
                    }))
                }
            />

            <form onSubmit={handleIdentification}>
                <Grid container spacing={2} mt={1}>

                    <Grid item xs={12} lg={12}>
                        <Box onClick={() => { if (!userIsLogged) setIsOpenModalChangeEmail(true) }} sx={{ cursor: 'pointer' }}>
                            <Typography variant="button">
                                E-mail
                            </Typography>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                                <Typography variant="subtitle2" color="text.secondary" textOverflow="ellipsis" whiteSpace={"nowrap"} overflow={"hidden"}>
                                    {identification.email.value}
                                </Typography>
                                {!userIsLogged &&
                                    <Box mt='-10px'>
                                        <IconButton>
                                            <EditIcon />
                                        </IconButton>
                                    </Box>
                                }
                            </Box>
                        </Box>
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <TextField
                            label="Primeiro Nome"
                            variant="outlined"
                            autoFocus={true}
                            disabled={userIsLogged}
                            value={identification.firstName.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setIdentification((prev) => ({
                                    ...prev,
                                    firstName: { value: event.target.value, error: false },
                                }))
                            }
                            error={identification.firstName.error}
                            helperText={getErrorMsg('firstName', 'Primeiro nome')}
                            fullWidth
                        />
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <TextField
                            label="Último Nome"
                            variant="outlined"
                            disabled={userIsLogged}
                            value={identification.lastName.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setIdentification((prev) => ({
                                    ...prev,
                                    lastName: { value: event.target.value, error: false },
                                }))
                            }
                            error={identification.lastName.error}
                            helperText={getErrorMsg('lastName', 'Último nome')}
                            fullWidth
                        />
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <TextField
                            label="CPF"
                            variant="outlined"
                            disabled={userIsLogged}
                            value={identification.cpf.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setIdentification((prev) => ({
                                    ...prev,
                                    cpf: { value: formatCpf(event.target.value), error: false },
                                }))
                            }
                            error={identification.cpf.error}
                            helperText={getErrorMsg('cpf', 'CPF')}
                            fullWidth
                        />
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <TextField
                            label="Telefone"
                            variant="outlined"
                            value={identification.phone.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setIdentification((prev) => ({
                                    ...prev,
                                    phone: { value: formatPhone(event.target.value), error: false },
                                }))
                            }
                            error={identification.phone.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />
                    </Grid>

                    <Grid item xs={12} lg={12}>
                        <CustomButton
                            title="Ir para a Entrega"
                            type="submit"
                            width='100%'
                        />
                    </Grid>
                </Grid>
            </form>
        </>
    )

    const renderIdentificationContent = () => (
        <Box mt={1}>
            <Typography variant="body2" color="text.secondary">
                {`Email: ${identification.email.value}`}
            </Typography>
            <Typography variant="body2" color="text.secondary">
                {`Nome: ${identification.firstName.value} ${identification.lastName.value}`}
            </Typography>
            <Typography variant="body2" color="text.secondary">
                {`Telefone: ${identification.phone.value}`}
            </Typography>
        </Box>
    )

    const renderShippingForm = () => (
        <form onSubmit={handleAddress}>
            <Grid container spacing={2} mt={1}>
                <Grid item xs={12} lg={12}>
                    <ButtonInput
                        value={address.cep.value}
                        onChange={handleChangeCep}
                        mask={formatCep}
                        error={address.cep.error || (!cepFound && address.cep.value.replace(/\D/g, '').length === 8)}
                        helperText={
                            address.cep.error ?
                                (address.cep.value.replace(/\D/g, '').length === 8 ? 'CEP não encontrado' : 'CEP inválido')
                                : ''
                        }
                        label='INFORME O CEP'
                        buttonLabel='APLICAR'
                        width={isLargeScreen ? '100%' : '100%'}
                    />
                    <Box mt={2}>
                        <ShippingCard
                            isLoadingCep={isLoadingCep}
                        />
                    </Box>
                </Grid>

                <>
                    <Grid item xs={12} lg={12}>
                        <TextField
                            label="Endereço"
                            variant="outlined"
                            value={address.street.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setAddress((prev) => ({
                                    ...prev,
                                    street: { value: event.target.value, error: false },
                                }))
                            }
                            error={address.street.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <TextField
                            label="Número"
                            variant="outlined"
                            value={address.number.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setAddress((prev) => ({
                                    ...prev,
                                    number: { value: event.target.value, error: false },
                                }))
                            }
                            error={address.number.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <TextField
                            label="Bairro"
                            variant="outlined"
                            value={address.neighborhood.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setAddress((prev) => ({
                                    ...prev,
                                    neighborhood: { value: event.target.value, error: false },
                                }))
                            }
                            error={address.neighborhood.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />

                    </Grid>
                    <Grid item xs={12} lg={12}>
                        <TextField
                            label="Complemento e referência"
                            variant="outlined"
                            value={address.complement.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setAddress((prev) => ({
                                    ...prev,
                                    complement: { value: event.target.value, error: false },
                                }))
                            }
                            error={address.complement.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />
                    </Grid>
                    <Grid item xs={12} lg={9}>
                        <TextField
                            label="Cidade"
                            variant="outlined"
                            disabled={true}
                            value={address.city.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setAddress((prev) => ({
                                    ...prev,
                                    city: { value: event.target.value, error: false },
                                }))
                            }
                            error={address.city.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />
                    </Grid>

                    <Grid item xs={4} lg={3}>
                        <TextField
                            label="UF"
                            variant="outlined"
                            disabled={true}
                            inputProps={{
                                maxLength: 2,
                            }}
                            value={address.state.value}
                            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                                setAddress((prev) => ({
                                    ...prev,
                                    state: { value: event.target.value, error: false },
                                }))
                            }
                            error={address.state.error}
                            helperText={getErrorMsg('phone', 'Telefone')}
                            fullWidth
                        />
                    </Grid>
                </>

                <Grid item xs={12} lg={12} mt={2}>
                    <CustomButton
                        title="Ir para o Pagamento"
                        type="submit"
                        width='100%'
                    />
                </Grid>
            </Grid>
        </form>
    )

    const renderShippingContent = () => {
        if (step === Steps.Identification)
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Aguardando o preenchimento dos dados
                </Typography>

            </Box>
        else
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Endereço: {address.street.value}, {address.number.value}
                </Typography>
            </Box>
    }

    const renderPaymentForm = () => {
        const payOptions: PayOptions[] = [
            {
                label: 'Pix',
                value: 'pix',
                icon: <MonetizationOnIcon />
            },
            {
                label: 'Cartão de crédito',
                value: 'creditCard',
                icon: <CreditCardIcon />
            },
        ]
        return (
            <Box mt={2} display="flex" flexDirection={'column'} sx={{ width: '100%' }}>
                <RadioGroup value={paymentType}>
                    {payOptions.map((payOp) => (
                        <div key={payOp.value} onClick={() => setPaymentType(payOp.value)}>
                            <Card sx={{ mt: 1 }} style={paymentType === payOp.value ? { borderStyle: 'solid', borderWidth: '2px', borderColor: 'black' } : {}}>
                                <Box sx={{ padding: '8px' }}>
                                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <FormControlLabel
                                            value={payOp.value}
                                            control={<Radio color="primary" />}
                                            label={
                                                <Typography variant="body1" component="div">
                                                    {payOp.label}
                                                </Typography>
                                            }
                                        />
                                        {payOp.icon}
                                    </Box>
                                </Box>
                            </Card>
                        </div>
                    ))}
                </RadioGroup>
            </Box>
        )
    }

    const renderPaymentContent = () => {
        if (step === Steps.Identification)
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Aguardando o preenchimento dos dados
                </Typography>

            </Box>
        else
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Forma de pagamento: cartão
                </Typography>
            </Box>
    }

    return (
        <Layout hideFooter={true}>
            <Container maxWidth="xl">
                <Grid container mt={4}>
                    <Grid item xs={12} lg={4} bgcolor={debugColors[0]} sx={{ border: 1, borderColor: '#ededed' }} pt={2} pl={4} pr={4}  >
                        <Box sx={{ display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
                            <Typography variant="h6">
                                IDENTIFICAÇÃO
                            </Typography>
                            {step !== Steps.Identification &&
                                <IconButton
                                    onClick={() => goToStep(Steps.Identification)}
                                    edge="start"
                                >
                                    <EditIcon />
                                </IconButton>
                            }
                        </Box>
                        <Divider />
                        {step === Steps.Identification ? renderIdentificationForm() : renderIdentificationContent()}
                    </Grid>
                    <Grid item xs={12} lg={4} bgcolor={debugColors[0]} sx={{ border: 1, borderColor: '#ededed' }} pt={2} pl={4} pr={4} pb={4}>
                        <Box sx={{ display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
                            <Typography variant="h6">
                                ENTREGA
                            </Typography>
                            {step === Steps.Payment &&
                                <IconButton
                                    onClick={() => goToStep(Steps.Shipping)}
                                    edge="start"
                                >
                                    <EditIcon />
                                </IconButton>
                            }
                        </Box>
                        <Divider />
                        {step === Steps.Shipping ? renderShippingForm() : renderShippingContent()}

                        <Box mt={4}>
                            <Typography variant="h6">
                                PAGAMENTO
                            </Typography>
                            <Divider />
                        </Box>
                        {step === Steps.Payment ? renderPaymentForm() : renderPaymentContent()}
                        <Box
                            visibility={step === Steps.Payment && paymentType === 'creditCard' ? 'visible' : 'hidden'}
                            height={step === Steps.Payment && paymentType === 'creditCard' ? 'auto' : '0px'}
                        >
                            {(identification.email.value && validateCpf(identification.cpf.value)) &&
                                <MercadoPagoCheckout
                                    amount={179} // TODO
                                    initialEmail={identification.email.value}
                                    initialDocument={identification.cpf.value}
                                />
                            }
                        </Box>
                    </Grid>

                    <Grid item xs={12} lg={4} bgcolor='#f8f4f4' sx={{ border: 1, borderColor: '#ededed' }} p={4}>
                        <Typography variant="h6">
                            RESUMO DA COMPRA
                        </Typography>
                        <Divider />
                        <Box mt={2}>
                            <Typography variant="body2" color="text.secondary">
                                Subtotal: R$ 199,90
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                                Frete: Grátis
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                                Cupom: 20
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                                Total: R$ 179,90
                            </Typography>
                        </Box>
                        {step === Steps.Payment &&
                            <Box mt={2}>
                                <CustomButton
                                    title="FINALIZAR COMPRA"
                                    onClick={debounce(handleBuy, 500)}
                                    width='100%'
                                />
                            </Box>
                        }
                    </Grid>
                </Grid>
            </Container>
        </Layout>
    );
}
