import React, { useEffect, useState } from 'react';
import Button from '@mui/material/Button';
import TextField from '@mui/material/TextField';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
import ReCAPTCHA from 'react-google-recaptcha';
import { CAPTCHA_KEY, validateEmail } from '../../utils/utils';
import api from '../api';
import { navigate } from 'gatsby';

interface ChangeEmailDialogProps {
  isOpen: boolean;
  value: string;
  onClose: () => void;
  onChange: (value: string) => void;
}

const ChangeEmailDialog: React.FC<ChangeEmailDialogProps> = ({ isOpen, value, onClose, onChange }) => {
  const recaptchaRef = React.useRef() as any;
  const [email, setEmail] = useState(value);
  const [wasUsed, setWasUsed] = useState(false);

  const handleLogin = () => {
    navigate('/login');
  };

  const handleClose = () => {
    onClose();
  };

  const handleSave = async () => {
    if (email.length < 3) {
      alert('Login inválido');
    } else {
      if (!validateEmail(email)) {
        alert('E-mail inválido');
        return;
      }
      let token;
      if (recaptchaRef && recaptchaRef.current) {
        token = await recaptchaRef?.current.executeAsync();
      }
      if (!token) {
        alert("Verifique o reCAPTCHA");
      }
      else {
        api.post("/v1/user/check-email", {
          captchaResponse: token,
          email,
          sendCode: false
        })
          .then((res) => {
            setTimeout(() => recaptchaRef?.current?.reset(), 500);
            const registered = res?.data?.registered ? true : false;
            if (registered) {
              setWasUsed(registered);
            } else {
              onChange(email);
              handleClose();
            }
          }).catch((e) => {
            setTimeout(() => recaptchaRef?.current?.reset(), 500);
            alert('Houve um erro, tente mais tarde.');
          });
      }
    }
  };

  const handleEmailChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setEmail(event.target.value);
  };

  const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    if (event.key === 'Enter') {
      handleSave();
    }
  };

  useEffect(() => {
    if (isOpen)
      setEmail(value);
  }, [isOpen]);

  useEffect(() => {
    if (wasUsed)
      setWasUsed(false);
  }, [email]);

  return (
    <>
      {isOpen &&
        <ReCAPTCHA
          ref={recaptchaRef}
          size="invisible"
          sitekey={CAPTCHA_KEY}
        />
      }
      <Dialog open={isOpen} fullWidth>
        <DialogTitle>Alterar e-mail</DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            margin="dense"
            id="name"
            label="E-mail"
            type="email"
            fullWidth
            variant="standard"
            value={email}
            onChange={handleEmailChange}
            onKeyDown={handleKeyDown}
            helperText={wasUsed ? 'Este e-mail já foi utilizado, faça login ou altere o e-mail' : ''}
            error={wasUsed}
          />
        </DialogContent>
        <DialogActions>
          {wasUsed &&
            <Button onClick={handleLogin} sx={{ color: '#1769aa' }}>Fazer login</Button>
          }
          <div style={{ flex: '1 0 0' }} />
          <Button onClick={handleClose}>Cancelar</Button>
          <Button onClick={handleSave} variant="contained">Salvar</Button>
        </DialogActions>
      </Dialog >
    </>
  );
};

export default ChangeEmailDialog;
